<svg viewBox="0 0 700 430" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="34" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Un objetivo móvil — obligación de dividendos x20, reserva sin cambios</text>
  <g font-family="sans-serif">
    <text x="20" y="66" fill="#a1a1aa" font-size="13">Pagos trimestrales de dividendos preferentes</text>
    <rect x="20" y="80" width="60" height="120" fill="#3f3f46" rx="4"/>
    <text x="50" y="76" fill="#a1a1aa" font-size="11" text-anchor="middle">1T 2025</text>
